input.card_css:
#scene-container {
  width: 100%;
  height: 100%;
  position: absolute;
  top: 0;
  left: 0;
}

.info-panel {
  position: absolute;
  top: 10px;
  right: 10px;
  width: 220px;
  background: rgba(0, 0, 0, 0.75);
  border-radius: 8px;
  padding: 12px;
  color: #ffffff;
  font-family: 'Segoe UI', Arial, sans-serif;
  font-size: 13px;
  z-index: 10;
  pointer-events: none;
  backdrop-filter: blur(4px);
  border: 1px solid rgba(255, 255, 255, 0.1);
}

.info-panel-header h3 {
  margin: 0 0 4px 0;
  font-size: 16px;
  color: #ffd700;
}

.info-panel-header .subtitle {
  margin: 0;
  font-size: 11px;
  color: #aaa;
}

.planet-info {
  margin-top: 12px;
  padding-top: 12px;
  border-top: 1px solid rgba(255, 255, 255, 0.15);
}

.planet-info .planet-name {
  font-size: 18px;
  font-weight: bold;
  color: #ffd700;
  margin: 0 0 8px 0;
}

.planet-info .planet-detail {
  margin: 4px 0;
  font-size: 12px;
  line-height: 1.5;
}

.planet-info .planet-detail strong {
  color: #ccc;
}

.info-text {
  color: #888;
  font-style: italic;
  margin: 0;
}

.controls-hint {
  margin-top: 12px;
  padding-top: 12px;
  border-top: 1px solid rgba(255, 255, 255, 0.15);
}

.controls-hint h4 {
  margin: 0 0 6px 0;
  font-size: 13px;
  color: #ccc;
}

.controls-hint ul {
  margin: 0;
  padding-left: 18px;
  list-style: none;
}

.controls-hint li {
  margin: 4px 0;
  font-size: 11px;
  color: #999;
  line-height: 1.4;
}

#labels-container {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 5;
}

.planet-label {
  color: #ffffff;
  font-family: 'Segoe UI', Arial, sans-serif;
  font-size: 12px;
  font-weight: bold;
  text-shadow: 0 0 4px rgba(0, 0, 0, 0.9), 0 0 8px rgba(0, 0, 0, 0.7);
  white-space: nowrap;
  text-align: center;
  transform: translate(-50%, -100%);
  padding: 2px 6px;
  pointer-events: none;
}

.loading {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: #ffffff;
  font-family: 'Segoe UI', Arial, sans-serif;
  text-align: center;
  z-index: 100;
  pointer-events: none;
}

.spinner {
  width: 40px;
  height: 40px;
  margin: 0 auto 12px;
  border: 3px solid rgba(255, 255, 255, 0.2);
  border-top-color: #ffd700;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.loading p {
  margin: 0;
  font-size: 14px;
  color: #ccc;
}

