// Solar System Visualization
// All planet textures loaded from Wikimedia Commons (CC BY 4.0)
// Fallback: procedural textures if texture loading fails

(function() {
  'use strict';

  // Planet data: name, distance, radius, orbitalPeriod (Earth years), rotationPeriod (days), axialTilt (degrees), color, textureUrl
  const PLANET_DATA = [
    { name: 'Mercury', distance: 3, radius: 0.35, orbitalPeriod: 0.24, rotationPeriod: 58.6, axialTilt: 0.03, color: 0x8c7e6d, textureUrl: 'https://upload.wikimedia.org/wikipedia/commons/9/92/Solarsystemscope_texture_2k_mercury.jpg', info: { type: 'Rocky Planet', diameter: '4,879 km', dayLength: '1407.6 hours', moons: 0, temp: '-173°C to 427°C' }},
    { name: 'Venus', distance: 5, radius: 0.55, orbitalPeriod: 0.62, rotationPeriod: -243, axialTilt: 177.4, color: 0xe8cda0, textureUrl: 'https://upload.wikimedia.org/wikipedia/commons/4/40/Solarsystemscope_texture_2k_venus_surface.jpg', info: { type: 'Rocky Planet', diameter: '12,104 km', dayLength: '5832 hours', moons: 0, temp: '462°C' }},
    { name: 'Earth', distance: 7, radius: 0.6, orbitalPeriod: 1.0, rotationPeriod: 1, axialTilt: 23.4, color: 0x2244aa, textureUrl: 'https://upload.wikimedia.org/wikipedia/commons/c/c3/Solarsystemscope_texture_2k_earth_daymap.jpg', info: { type: 'Rocky Planet', diameter: '12,742 km', dayLength: '24 hours', moons: 1, temp: '-88°C to 58°C' }},
    { name: 'Mars', distance: 9, radius: 0.45, orbitalPeriod: 1.88, rotationPeriod: 1.03, axialTilt: 25.2, color: 0xc1440e, textureUrl: 'https://upload.wikimedia.org/wikipedia/commons/4/46/Solarsystemscope_texture_2k_mars.jpg', info: { type: 'Rocky Planet', diameter: '6,779 km', dayLength: '24.6 hours', moons: 2, temp: '-153°C to 20°C' }},
    { name: 'Jupiter', distance: 14, radius: 1.8, orbitalPeriod: 11.86, rotationPeriod: 0.41, axialTilt: 3.1, color: 0xd4a574, textureUrl: 'https://upload.wikimedia.org/wikipedia/commons/b/be/Solarsystemscope_texture_2k_jupiter.jpg', info: { type: 'Gas Giant', diameter: '139,820 km', dayLength: '9.9 hours', moons: 95, temp: '-145°C' }},
    { name: 'Saturn', distance: 19, radius: 1.5, orbitalPeriod: 29.46, rotationPeriod: 0.44, axialTilt: 26.7, color: 0xe8d5a3, textureUrl: 'https://upload.wikimedia.org/wikipedia/commons/1/1e/Solarsystemscope_texture_8k_saturn.jpg', hasRings: true, info: { type: 'Gas Giant', diameter: '116,460 km', dayLength: '10.7 hours', moons: 146, temp: '-178°C' }},
    { name: 'Uranus', distance: 24, radius: 1.0, orbitalPeriod: 84.01, rotationPeriod: -0.72, axialTilt: 97.8, color: 0x72b5c4, textureUrl: 'https://upload.wikimedia.org/wikipedia/commons/9/95/Solarsystemscope_texture_2k_uranus.jpg', info: { type: 'Ice Giant', diameter: '50,724 km', dayLength: '17.2 hours', moons: 28, temp: '-224°C' }},
    { name: 'Neptune', distance: 28, radius: 0.95, orbitalPeriod: 164.8, rotationPeriod: 0.67, axialTilt: 28.3, color: 0x3355bb, textureUrl: 'https://upload.wikimedia.org/wikipedia/commons/1/1e/Solarsystemscope_texture_2k_neptune.jpg', info: { type: 'Ice Giant', diameter: '49,244 km', dayLength: '16.1 hours', moons: 16, temp: '-218°C' }}
  ];

  let scene, camera, renderer, controls;
  let planets = [];
  let orbitLines = [];
  let sun;
  let raycaster, mouse;
  let clock;
  let labelElements = [];
  let textureLoader;
  let loadingCount = 0;
  let totalTextures = 0;

  // Initialize the scene
  function init() {
    clock = new THREE.Clock();
    raycaster = new THREE.Raycaster();
    mouse = new THREE.Vector2();
    textureLoader = new THREE.TextureLoader();

    // Create scene
    scene = new THREE.Scene();

    // Create camera
    const container = container || document.getElementById('scene-container');
    const width = container.clientWidth;
    const height = container.clientHeight;
    camera = new THREE.PerspectiveCamera(60, width / height, 0.1, 1000);
    camera.position.set(20, 15, 25);
    camera.lookAt(0, 0, 0);

    // Create renderer
    renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(width, height);
    renderer.setPixelRatio(window.devicePixelRatio);
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    container.appendChild(renderer.domElement);

    // Add OrbitControls
    import('https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/controls/OrbitControls.js').then((module) => {
      controls = new module.OrbitControls(camera, renderer.domElement);
      controls.enableDamping = true;
      controls.dampingFactor = 0.05;
      controls.minDistance = 5;
      controls.maxDistance = 100;
    }).catch(() => {
      console.warn('OrbitControls failed to load, using default camera');
    });

    // Create starfield
    createStarfield();

    // Create Sun
    createSun();

    // Create planets
    createPlanets();

    // Add event listeners
    window.addEventListener('resize', onWindowResize);
    renderer.domElement.addEventListener('click', onCanvasClick);

    // Start animation loop
    animate();
  }

  // Create starfield background
  function createStarfield() {
    const starsGeometry = new THREE.BufferGeometry();
    const starCount = 5000;
    const positions = new Float32Array(starCount * 3);

    for (let i = 0; i < starCount; i++) {
      const i3 = i * 3;
      const radius = 200 + Math.random() * 300;
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      positions[i3] = radius * Math.sin(phi) * Math.cos(theta);
      positions[i3 + 1] = radius * Math.sin(phi) * Math.sin(theta);
      positions[i3 + 2] = radius * Math.cos(phi);
    }

    starsGeometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));

    const starsMaterial = new THREE.PointsMaterial({
      color: 0xffffff,
      size: 0.5,
      sizeAttenuation: true
    });

    const stars = new THREE.Points(starsGeometry, starsMaterial);
    scene.add(stars);
  }

  // Create the Sun
  function createSun() {
    const sunGeometry = new THREE.SphereGeometry(2.5, 64, 64);
    const sunMaterial = new THREE.MeshBasicMaterial({
      color: 0xffdd33
    });

    // Try to load texture, fallback to color
    let textureLoaded = false;
    textureLoader.load(
      'https://upload.wikimedia.org/wikipedia/commons/c/cb/Solarsystemscope_texture_2k_sun.jpg',
      (texture) => {
        sunMaterial.map = texture;
        sunMaterial.color.set(0xffffff);
        sunMaterial.needsUpdate = true;
        textureLoaded = true;
      },
      undefined,
      () => {
        console.warn('Sun texture failed to load, using color fallback');
      }
    );

    sun = new THREE.Mesh(sunGeometry, sunMaterial);
    sun.position.set(0, 0, 0);
    scene.add(sun);

    // Add glow effect
    const glowGeometry = new THREE.SphereGeometry(2.8, 32, 32);
    const glowMaterial = new THREE.MeshBasicMaterial({
      color: 0xffaa00,
      transparent: true,
      opacity: 0.15,
      side: THREE.BackSide
    });
    const glow = new THREE.Mesh(glowGeometry, glowMaterial);
    sun.add(glow);

    // Add point light from the Sun
    const sunLight = new THREE.PointLight(0xffffff, 2, 100);
    sunLight.castShadow = true;
    sun.add(sunLight);

    // Add ambient light for visibility
    const ambientLight = new THREE.AmbientLight(0x222233, 0.5);
    scene.add(ambientLight);
  }

  // Create all planets
  function createPlanets() {
    PLANET_DATA.forEach((data, index) => {
      const planetGroup = new THREE.Group();

      // Create planet mesh
      const geometry = new THREE.SphereGeometry(data.radius, 32, 32);
      const material = new THREE.MeshPhongMaterial({
        color: data.color,
        shininess: 25
      });

      // Load texture with fallback
      let textureLoaded = false;
      textureLoader.load(
        data.textureUrl,
        (texture) => {
          material.map = texture;
          material.color.set(0xffffff);
          material.needsUpdate = true;
          textureLoaded = true;
        },
        undefined,
        () => {
          console.warn(`${data.name} texture failed to load, using procedural color`);
        }
      );

      const planet = new THREE.Mesh(geometry, material);
      planet.castShadow = true;
      planet.receiveShadow = true;
      planet.userData = { name: data.name, index: index };
      planetGroup.add(planet);

      // Apply axial tilt
      planet.rotation.z = (data.axialTilt * Math.PI) / 180;

      // Add Saturn's rings
      if (data.hasRings) {
        const ringGeometry = new THREE.RingGeometry(data.radius * 1.3, data.radius * 2.2, 64);
        const ringMaterial = new THREE.MeshPhongMaterial({
          color: 0xc8b080,
          side: THREE.DoubleSide,
          transparent: true,
          opacity: 0.7
        });
        const ring = new THREE.Mesh(ringGeometry, ringMaterial);
        ring.rotation.x = Math.PI / 2;
        planet.add(ring);
      }

      // Create orbital path line
      const orbitGeometry = new THREE.BufferGeometry();
      const orbitPoints = [];
      const segments = 256;
      for (let i = 0; i <= segments; i++) {
        const angle = (i / segments) * Math.PI * 2;
        orbitPoints.push(Math.cos(angle) * data.distance, 0, Math.sin(angle) * data.distance);
      }
      orbitGeometry.setAttribute('position', new THREE.Float32BufferAttribute(orbitPoints, 3));
      const orbitMaterial = new THREE.LineBasicMaterial({
        color: 0xffffff,
        transparent: true,
        opacity: 0.15
      });
      const orbitLine = new THREE.Line(orbitGeometry, orbitMaterial);
      scene.add(orbitLine);
      orbitLines.push(orbitLine);

      // Create label element
      const labelDiv = document.createElement('div');
      labelDiv.className = 'planet-label';
      labelDiv.textContent = data.name;
      labelDiv.style.display = 'none';
      document.getElementById('labels-container').appendChild(labelDiv);
      labelElements.push({ element: labelDiv, planet: planetGroup });

      // Store planet data
      planetGroup.userData = {
        name: data.name,
        distance: data.distance,
        orbitalPeriod: data.orbitalPeriod,
        rotationPeriod: data.rotationPeriod,
        axialTilt: data.axialTilt,
        info: data.info,
        angle: Math.random() * Math.PI * 2 // Random initial phase
      };

      scene.add(planetGroup);
      planets.push(planetGroup);
    });
  }

  // Handle window resize
  function onWindowResize() {
    const container = container || document.getElementById('scene-container');
    const width = container.clientWidth;
    const height = container.clientHeight;
    camera.aspect = width / height;
    camera.updateProjectionMatrix();
    renderer.setSize(width, height);
  }

  // Handle canvas click for planet selection
  function onCanvasClick(event) {
    const container = container || document.getElementById('scene-container');
    const rect = container.getBoundingClientRect();
    mouse.x = ((event.clientX - rect.left) / rect.width) * 2 - 1;
    mouse.y = -((event.clientY - rect.top) / rect.height) * 2 + 1;

    raycaster.setFromCamera(mouse, camera);
    const planetMeshes = planets.map(p => p.children[0]);
    const intersects = raycaster.intersectObjects(planetMeshes);

    if (intersects.length > 0) {
      const selectedPlanet = intersects[0].object;
      const planetData = selectedPlanet.userData;
      updateInfoPanel(planetData);
    }
  }

  // Update info panel with planet details
  function updateInfoPanel(planetData) {
    const infoDiv = document.getElementById('planet-info');
    infoDiv.innerHTML = `
      <div class="planet-name">${planetData.name}</div>
      <div class="planet-detail"><strong>Type:</strong> ${planetData.info.type}</div>
      <div class="planet-detail"><strong>Diameter:</strong> ${planetData.info.diameter}</div>
      <div class="planet-detail"><strong>Day Length:</strong> ${planetData.info.dayLength}</div>
      <div class="planet-detail"><strong>Moons:</strong> ${planetData.info.moons}</div>
      <div class="planet-detail"><strong>Temperature:</strong> ${planetData.info.temp}</div>
    `;
  }

  // Update planet positions and labels
  function updatePlanets(deltaTime) {
    planets.forEach((planetGroup, index) => {
      const speed = (2 * Math.PI) / (planetGroup.userData.orbitalPeriod * 60);
      planetGroup.userData.angle += speed * deltaTime;

      const x = Math.cos(planetGroup.userData.angle) * planetGroup.userData.distance;
      const z = Math.sin(planetGroup.userData.angle) * planetGroup.userData.distance;
      planetGroup.position.set(x, 0, z);

      // Rotate planet on its axis
      const rotationSpeed = (2 * Math.PI) / (Math.abs(planetGroup.userData.rotationPeriod) * 10);
      const direction = planetGroup.userData.rotationPeriod > 0 ? 1 : -1;
      planetGroup.children[0].rotation.y += rotationSpeed * direction * deltaTime * 0.1;

      // Update label position
      const labelData = labelElements[index];
      if (labelData) {
        const worldPosition = new THREE.Vector3();
        planetGroup.children[0].getWorldPosition(worldPosition);
        const screenPosition = worldPosition.clone().project(camera);

        const container = container || document.getElementById('scene-container');
        const x2 = (screenPosition.x * 0.5 + 0.5) * container.clientWidth;
        const y2 = (-screenPosition.y * 0.5 + 0.5) * container.clientHeight;

        labelData.element.style.left = x2 + 'px';
        labelData.element.style.top = (y2 - 20) + 'px';
        labelData.element.style.display = 'block';
      }
    });
  }

  // Animation loop
  function animate() {
    requestAnimationFrame(animate);
    const deltaTime = clock.getDelta();

    // Rotate Sun slowly
    if (sun) {
      sun.rotation.y += deltaTime * 0.05;
    }

    // Update planet positions
    updatePlanets(deltaTime);

    // Update controls
    if (controls) {
      controls.update();
    }

    // Render scene
    renderer.render(scene, camera);
  }

  // Initialize when Three.js is available
  if (typeof THREE !== 'undefined') {
    init();
  } else {
    // Wait for Three.js to load
    const checkThree = setInterval(() => {
      if (typeof THREE !== 'undefined') {
        clearInterval(checkThree);
        init();
      }
    }, 100);
  }
})();
